class NetworkSessionManager:
    def __init__(self):
        self.sessions: dict[int, dict[str, any]] = {}
        self.next_session_id: int = 1

    def create_session(self, timeout: int) -> int:
        session_id: int = self.next_session_id
        self.sessions[session_id] = {
            'timeout': timeout,
            'status': 'active'
        }
        self.next_session_id += 1
        return session_id

    def close_session(self, session_id: int) -> None:
        if session_id not in self.sessions:
            print(f"Error: Session ID {session_id} does not exist.")
            return
        self.sessions[session_id]['status'] = 'closed'

    def modify_session(self, session_id: int, new_timeout: int) -> None:
        if session_id not in self.sessions:
            print(f"Error: Session ID {session_id} does not exist.")
            return
        self.sessions[session_id]['timeout'] = new_timeout

    def get_session_status(self, session_id: int) -> str:
