import java.util.HashMap;
import java.util.Map;

public class SmartHomeSystem {
    // Constants
    private static final String[] ROOMS = {"Living Room", "Bedroom", "Kitchen", "Bathroom"};
    private static final int DEFAULT_BRIGHTNESS = 10;
    private static final boolean DEFAULT_STATUS = false;

    // State storage
    private static class RoomState {
        boolean lightsOn;
        int brightness;

        RoomState(boolean lightsOn, int brightness) {
            this.lightsOn = lightsOn;
            this.brightness = brightness;
        }
    }

    private static final Map<String, RoomState> roomStates = new HashMap<>();
    private static final StringBuilder commandHistory = new StringBuilder();

    static {
        for (String room : ROOMS) {
            roomStates.put(room, new RoomState(DEFAULT_STATUS, DEFAULT_BRIGHTNESS));
        }
    }

    public static void turnOn(String room) {
        if (roomStates.containsKey(room)) {
            roomStates.get(room).lightsOn = true;
            commandHistory.append("turnOn(").append(room).append(")\n");
        } else {
            System.out.println("Error: Room " + room + " not found.");
        }
    }

    public static void turnOff(String room) {
        if (roomStates.containsKey(room)) {
            roomStates.get(room).lightsOn = false;
            commandHistory.append("turnOff(").append(room).append(")\n");
        } else {
            System.out.println("Error: Room " + room + " not found.");
        }
    }

    public static void adjustBrightness(String room, int level) {
        if (roomStates.containsKey(room)) {
            roomStates.get(room).brightness = level;
            commandHistory.append("adjustBrightness(").append(room).append(", ").append(level).append(")\n");
        } else {
            System.out.println("Error: Room " + room + " not found.");
        }
    }

    public static String checkStatus(String room) {
        if (roomStates.containsKey(room)) {
            RoomState state = roomStates.get(room);
            String status = state.lightsOn ? "On" : "Off";
            commandHistory.append("checkStatus(").append(room).append(")\n");
            return "Room: " + room + ", Status: " + status + ", Brightness Level: " + state.brightness;
        } else {
            return "Error: Room " + room + " not found.";
        }
    }

    public static void main(String[] args) {
        turnOn("Living Room");
        adjustBrightness("Living Room", 15);
        System.out.println(checkStatus("Living Room"));
        turnOff("Living Room");
        turnOn("Bathroom");
        System.out.println(checkStatus("Bathroom"));
        System.out.println(checkStatus("Hallway"));  // Room not found
    }
}
