class HardwareStore {
public:
    void addItem(const std::string& itemName, int quantity, double price) {
        if (inventory.find(itemName) != inventory.end()) {
            std::cout << "Error: Item already exists. Use UPDATE to modify.\n";
            return;
        }
        inventory[itemName] = {quantity, price};
    }

    void removeItem(const std::string& itemName) {
        if (inventory.find(itemName) == inventory.end()) {
            std::cout << "Error: Item does not exist.\n";
            return;
        }
        inventory.erase(itemName);
    }

    void updateItem(const std::string& itemName, int newQuantity, double newPrice) {
        if (inventory.find(itemName) == inventory.end()) {
            std::cout << "Error: Item does not exist.\n";
            return;
        }
        inventory[itemName] = {newQuantity, newPrice};
    }

    void displayInventory() const {
        std::cout << std::setw(10) << "Item" << std::setw(10) << "Quantity" << std::setw(10) << "Price\n";
        for (const auto& item : inventory) {
            std::cout << std::setw(10) << item.first
                      << std::setw(10) << item.second.first
                      << std::setw(10) << item.second.second << "\n";
