function processChartData(rawData) {
    var bucketsByHour, dataPoint, hour, hourBucket;
    var averageValuesByHour;

    bucketsByHour = {};

    for (var i = 0; i < rawData.length; i++) {
        dataPoint = rawData[i];
        hour = new Date(dataPoint.timestamp).getHours();

        if (!bucketsByHour[hour]) {
            bucketsByHour[hour] = [];
        }

        hourBucket = bucketsByHour[hour];
        hourBucket.push(dataPoint.value);
    }

    averageValuesByHour = {};

    for (hour in bucketsByHour) {
        var values, sum, averageValue;
        values = bucketsByHour[hour];
        sum = 0;

        for (var j = 0; j < values.length; j++) {
            sum += values[j];
        }

        averageValue = sum / values.length;
        averageValuesByHour[hour] = averageValue;
    }

    return averageValuesByHour;
}
