class TimeTracker:
    def __init__(self):
        self.projects = {}

    def add_project(self, project_name):
        if project_name in self.projects:
            print(f"Error: Project '{project_name}' already exists.")
            return
        self.projects[project_name] = []
        print(f"Project '{project_name}' added.")

    def start_time(self, project_name, time):
        if project_name not in self.projects:
            print(f"Error: Project '{project_name}' does not exist.")
            return
        if len(self.projects[project_name]) % 2 != 0:
            print(f"Error: Stop time already recorded for project '{project_name}'. Start a new session.")
            return
        self.projects[project_name].append(time)
        print(f"Start time '{time}' recorded for project '{project_name}'.")

    def stop_time(self, project_name, time):
        if project_name not in self.projects:
            print(f"Error: Project '{project_name}' does not exist.")
            return
        if len(self.projects[project_name]) % 2 == 0:
            print(f"Error: Start time not recorded for project '{project_name}'.")
            return
        self.projects[project_name].append(time)
        print(f"Stop time '{time}' recorded for project '{project_name}'.")

    def report(self, project_name):
        if project_name not in self.projects:
            print(f"Error: Project '{project_name}' does not exist.")
            return
        total_minutes = 0
        times = self.projects[project_name]
        for i in range(0, len(times), 2):
            start = self.convert_to_minutes(times[i])
            stop = self.convert_to_minutes(times[i + 1])
            total_minutes += stop - start
        hours = total_minutes // 60
        minutes = total_minutes % 60
        print(f"Total time for project '{project_name}': {hours} hours and {minutes} minutes.")

    def convert_to_minutes(self, time):
        hours, minutes = map(int, time.split(':'))
        return hours * 60 + minutes


def main():
    tracker = TimeTracker()
    commands = [
        ("ADD_PROJECT", "Project1"),
        ("START_TIME", "Project1", "09:00"),
        ("STOP_TIME", "Project1", "11:30"),
        ("REPORT", "Project1"),
        ("ADD_PROJECT", "Project2"),
        ("START_TIME", "Project2", "13:45"),
        ("STOP_TIME", "Project2", "15:15"),
        ("REPORT", "Project2"),
        ("REPORT", "NonExistentProject")
    ]

    for command in commands:
        if command[0] == "ADD_PROJECT":
            tracker.add_project(command[1])
        elif command[0] == "START_TIME":
            tracker.start_time(command[1], command[2])
        elif command[0] == "STOP_TIME":
            tracker.stop_time(command[1], command[2])
        elif command[0] == "REPORT":
            tracker.report(command[1])


if __name__ == "__main__":
    main()
