function manageTemperatureRecords() {
    const records = {};

    return {
        addRecord(location, temperature) {
            const date = new Date().toISOString().slice(0, 10);
            if (!records[location]) {
                records[location] = [];
            }
            records[location].push({ date, temperature });
        },

        getAverage(location) {
            if (!records[location]) {
                return `Error: Location ${location} does not exist.`;
            }

            const locationRecords = records[location];
            const numberOfRecords = locationRecords.length;

            if (numberOfRecords === 0) {
                return `Error: No records available to calculate an average for location ${location}.`;
            }

            const totalTemperature = locationRecords.reduce((sum, record) => sum + record.temperature, 0);
            const averageTemperature = totalTemperature / numberOfRecords;
            return averageTemperature;
        },

        removeRecord(location, date) {
            if (!records[location]) {
                return `Error: Location ${location} does not exist.`;
            }

            records[location] = records[location].filter(record => record.date !== date);
        },

        updateRecord(location, date, newTemperature) {
            if (!records[location]) {
                return `Error: Location ${location} does not exist.`;
            }

            const recordToUpdate = records[location].find(record => record.date === date);
            if (recordToUpdate) {
                recordToUpdate.temperature = newTemperature;
            } else {
                return `Error: No record found for date ${date} at location ${location}.`;
            }
        }
    };
}
