use std::collections::HashMap;

struct FileManagementSystem {
    files: HashMap<String, String>,
}

impl FileManagementSystem {
    pub fn new() -> Self {
        FileManagementSystem {
            files: HashMap::new(),
        }
    }

    pub fn create_file(&mut self, path: &str, content: &str) {
        self.files.insert(path.to_string(), content.to_string());
    }

    pub fn read_file(&self, path: &str) -> Result<&str, &str> {
        match self.files.get(path) {
            Some(content) => Ok(content),
            None => Err("Error: File does not exist."),
        }
    }

    pub fn update_file(&mut self, path: &str, new_content: &str) -> Result<(), &str> {
        match self.files.get_mut(path) {
            Some(content) => {
                *content = new_content.to_string();
                Ok(())
            }
            None => Err("Error: File does not exist."),
        }
    }

    pub fn delete_file(&mut self, path: &str) -> Result<(), &str> {
        if self.files.remove(path).is_some() {
            Ok(())
        } else {
            Err("Error: File does not exist.")
        }
    }

    protected fn file_exists(&self, path: &str) -> bool {
        self.files.contains_key(path)
    }    
}
