#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Process {
    char name[50];
    int priority;
    struct Process* next;
} Process;

Process* head = NULL;

void add_process(char* name, int priority) {
    Process* new_process;
    Process* current;
    Process* prev;

    new_process = (Process*) malloc(sizeof(Process));
    strcpy(new_process->name, name);
    new_process->priority = priority;
    new_process->next = NULL;

    if (head == NULL || head->priority > priority) {
        new_process->next = head;
        head = new_process;
        return;
    }

    prev = NULL;
    current = head;
    while (current != NULL && current->priority <= priority) {
        prev = current;
        current = current->next;
    }

    prev->next = new_process;
    new_process->next = current;
}

void kill_process(char* name) {
    Process* current;
    Process* prev;

    prev = NULL;
    current = head;
    while (current != NULL) {
        if (strcmp(current->name, name) == 0) {
            if (prev == NULL) {
                head = current->next;
            } else {
                prev->next = current->next;
            }
            free(current);
            return;
        }
        prev = current;
        current = current->next;
    }
}

void kill_priority(int priority) {
    Process* current;
    Process* prev;
    Process* temp;

    prev = NULL;
    current = head;
    while (current != NULL) {
        if (current->priority == priority) {
            if (prev == NULL) {
                head = current->next;
            } else {
                prev->next = current->next;
            }
            temp = current;
            current = current->next;
            free(temp);
            continue;
        }
        prev = current;
        current = current->next;
    }
}

void list_processes() {
    Process* current;
    current = head;
    while (current != NULL) {
        printf("Name: %s, Priority: %d\n", current->name, current->priority);
        current = current->next;
    }
}

int main() {
    char command[50];
    char name[50];
    int priority;

    while (1) {
        printf("Enter command: ");
        scanf("%s", command);

        if (strcmp(command, "ADD") == 0) {
            scanf("%s %d", name, &priority);
            add_process(name, priority);
        } else if (strcmp(command, "KILL") == 0) {
            scanf("%s", name);
            kill_process(name);
        } else if (strcmp(command, "KILL_PRIORITY") == 0) {
            scanf("%d", &priority);
            kill_priority(priority);
        } else if (strcmp(command, "LIST") == 0) {
            list_processes();
        } else {
            printf("Unknown command\n");
        }
    }

    return 0;
}
