import javax.swing.*;
import java.awt.*;
import java.awt.event.ActionEvent;
import java.awt.event.ActionListener;

public class BasicCalculator extends JFrame {

    private JTextField inputField1;
    private JTextField inputField2;
    private JTextField resultField;
    private JButton addButton;
    private JButton subtractButton;
    private JButton multiplyButton;
    private JButton divideButton;

    public BasicCalculator() {
        setTitle("Basic Calculator");
        setSize(400, 200);
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setLayout(new GridLayout(5, 2));

        inputField1 = new JTextField();
        inputField2 = new JTextField();
        resultField = new JTextField();
        resultField.setEditable(false);

        addButton = new JButton("Add");
        subtractButton = new JButton("Subtract");
        multiplyButton = new JButton("Multiply");
        divideButton = new JButton("Divide");

        add(new JLabel("Input 1:"));
        add(inputField1);
        add(new JLabel("Input 2:"));
        add(inputField2);
        add(new JLabel("Result:"));
        add(resultField);
        add(addButton);
        add(subtractButton);
        add(multiplyButton);
        add(divideButton);

        addButton.addActionListener(new OperationListener());
        subtractButton.addActionListener(new OperationListener());
        multiplyButton.addActionListener(new OperationListener());
        divideButton.addActionListener(new OperationListener());
    }

    private synchronized double add(double a, double b) {
        return a + b;
    }

    private synchronized double subtract(double a, double b) {
        return a - b;
    }

    private synchronized double multiply(double a, double b) {
        return a * b;
    }

    private synchronized double divide(double a, double b) {
        if (b == 0) throw new ArithmeticException("Cannot divide by zero");
        return a / b;
    }

    private class OperationListener implements ActionListener {
        @Override
        public void actionPerformed(ActionEvent e) {
            try {
                double num1 = Double.parseDouble(inputField1.getText());
                double num2 = Double.parseDouble(inputField2.getText());
                double result;
                if (e.getSource() == addButton) {
                    result = add(num1, num2);
                } else if (e.getSource() == subtractButton) {
                    result = subtract(num1, num2);
                } else if (e.getSource() == multiplyButton) {
                    result = multiply(num1, num2);
                } else if (e.getSource() == divideButton) {
                    result = divide(num1, num2);
                } else {
                    return;
                }
                resultField.setText(String.valueOf(result));
            } catch (NumberFormatException ex) {
                JOptionPane.showMessageDialog(BasicCalculator.this, "Invalid input", "Error", JOptionPane.ERROR_MESSAGE);
            } catch (ArithmeticException ex) {
                JOptionPane.showMessageDialog(BasicCalculator.this, ex.getMessage(), "Error", JOptionPane.ERROR_MESSAGE);
            }
        }
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> new BasicCalculator().setVisible(true));
    }
}
