use std::collections::HashMap;

struct EventManager {
    events: HashMap<String, String>,
}

impl EventManager {
    /// Creates a new `EventManager`.
    fn new() -> Self {
        EventManager {
            events: HashMap::new(),
        }
    }

    /// Adds a new event with the specified name and date.
    fn add_event(&mut self, name: String, date: String) {
        self.events.insert(name, date);
    }

    /// Removes an event by its name. Returns an error message if the event does not exist.
    fn remove_event(&mut self, name: String) -> Result<(), String> {
        if self.events.remove(&name).is_none() {
            Err(format!("Event '{}' does not exist.", name))
        } else {
            Ok(())
        }
    }

    /// Retrieves the date of an event by its name, returning `None` if the event does not exist.
    fn get_event(&self, name: String) -> Option<String> {
        self.events.get(&name).cloned()
    }

    /// Returns a list of all event names currently registered.
    fn list_events(&self) -> Vec<String> {
        self.events.keys().cloned().collect()
    }
}

fn main() {
    let mut manager = EventManager::new();

    // Example usage
    manager.add_event("Yoga Class".to_string(), "2023-10-25".to_string());
    manager.add_event("Cooking Workshop".to_string(), "2023-11-03".to_string());

    match manager.get_event("Yoga Class".to_string()) {
        Some(date) => println!("Yoga Class is on: {}", date),
        None => println!("Yoga Class not found."),
    }

    if let Err(e) = manager.remove_event("Yoga Class".to_string()) {
        println!("{}", e);
    }

    for event in manager.list_events() {
        println!("Event: {}", event);
    }
}
