function manageTodos(command, args) {
    let tasksList = [];
    let taskIdCounter = 0;

    function addTask(taskDescription) {
        const newTask = {
            task_id: taskIdCounter++,
            description: taskDescription,
            completed: false
        };
        tasksList.push(newTask);
    }

    function completeTask(taskId) {
        const taskIndex = tasksList.findIndex(task => task.task_id === taskId);
        if (taskIndex !== -1) {
            tasksList[taskIndex].completed = true;
        } else {
            return `Error: Task with ID ${taskId} does not exist.`;
        }
    }

    function deleteTask(taskId) {
        const taskIndex = tasksList.findIndex(task => task.task_id === taskId);
        if (taskIndex !== -1) {
            tasksList.splice(taskIndex, 1);
        } else {
            return `Error: Task with ID ${taskId} does not exist.`;
        }
    }

    function listTasks() {
        return tasksList.map(task => 
            `ID: ${task.task_id}, Description: ${task.description}, Completed: ${task.completed}`
        ).join('\n');
    }

    switch (command) {
        case 'add':
            if (typeof args === 'string') addTask(args);
            break;
        case 'complete':
            if (typeof args === 'number') return completeTask(args);
            break;
        case 'delete':
            if (typeof args === 'number') return deleteTask(args);
            break;
        case 'list':
            return listTasks();
        default:
            return 'Invalid command.';
    }
}
