struct SubscriptionOptions {
    int user_id;
    bool subscribed_to_newsletter = true;
    std::string subscription_date;
};

std::mutex subscription_mutex;

void adjust_subscription(SubscriptionOptions options) {
    int user_id = options.user_id;
    bool subscribed_to_newsletter = options.subscribed_to_newsletter;
    std::string subscription_date = options.subscription_date;

    if (subscription_date.empty()) {
        std::time_t now = std::chrono::system_clock::to_time_t(std::chrono::system_clock::now());
        subscription_date = std::ctime(&now);
        subscription_date.erase(subscription_date.find_last_not_of(" \n\r\t") + 1);
    }

    std::lock_guard<std::mutex> lock(subscription_mutex);

    // Simulate updating subscription details
    subscribed_to_newsletter = !subscribed_to_newsletter;  // Toggle subscription status

    // Display updated subscription details
    std::cout << "User ID: " << user_id << std::endl;
    std::cout << "Subscribed to Newsletter: " << (subscribed_to_newsletter ? "Yes" : "No") << std::endl;
    std::cout << "Subscription Date: " << subscription_date << std::endl;
}

int main() {
