    public TrafficLightSystem() {
        this.currentLight = INITIAL_LIGHT_COLOR;
        this.delaySeconds = 0;
    }

    public void changeLight(String color) {
        if (color.equals("Green") || color.equals("Red") || color.equals("Yellow")) {
            currentLight = color;
        }
    }

    public String getCurrentLight() {
        return currentLight;
    }

    public void addDelay(int seconds) {
        this.delaySeconds = seconds;
    }

    public void nextLight() {
        try {
            Thread.sleep(delaySeconds * 1000);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        switch (currentLight) {
            case "Red":
                currentLight = "Green";
                break;
            case "Green":
                currentLight = "Yellow";
                break;
            case "Yellow":
                currentLight = "Red";
                break;
        }
        delaySeconds = 0;
    }

    public static void main(String[] args) {
        TrafficLightSystem tls = new TrafficLightSystem();
        tls.addDelay(5);
        tls.nextLight();
        System.out.println("Current Light: " + tls.getCurrentLight());
