#define MAX_SETTINGS 100
#define MAX_NAME_LENGTH 50
#define MAX_VALUE_LENGTH 100

typedef struct {
    char name[MAX_NAME_LENGTH];
    char value[MAX_VALUE_LENGTH];
    char defaultValue[MAX_VALUE_LENGTH];
} Setting;

Setting settings[MAX_SETTINGS];
int settingCount;

void initializeSettings();
void setSetting(const char *name, const char *value);
const char* getSetting(const char *name);
void resetSetting(const char *name);
void listAllSettings();

int main() {
    initializeSettings();
    setSetting("volume", "50");
    printf("Volume: %s\n", getSetting("volume"));
    listAllSettings();
    resetSetting("volume");
    printf("Volume after reset: %s\n", getSetting("volume"));
    return 0;
}

void initializeSettings() {
    int i;
    settingCount = 0;
    for (i = 0; i < MAX_SETTINGS; i++) {
        settings[i].name[0] = '\0';
        settings[i].value[0] = '\0';
        settings[i].defaultValue[0] = '\0';
    }
}

void setSetting(const char *name, const char *value) {
    int i;
    for (i = 0; i < settingCount; i++) {
        if (strcmp(settings[i].name, name) == 0) {
            strcpy(settings[i].value, value);
            return;
        }
    }
    if (settingCount < MAX_SETTINGS) {
        strcpy(settings[settingCount].name, name);
        strcpy(settings[settingCount].value, value);
        strcpy(settings[settingCount].defaultValue, value);
        settingCount++;
    }
}

const char* getSetting(const char *name) {
    int i;
    for (i = 0; i < settingCount; i++) {
        if (strcmp(settings[i].name, name) == 0) {
            return settings[i].value;
        }
    }
    return "Error: Setting not found";
}

void resetSetting(const char *name) {
    int i;
    for (i = 0; i < settingCount; i++) {
        if (strcmp(settings[i].name, name) == 0) {
            strcpy(settings[i].value, settings[i].defaultValue);
            return;
        }
    }
    printf("Error: Setting not found\n");
}

void listAllSettings() {
    int i;
    for (i = 0; i < settingCount; i++) {
        printf("%s: %s\n", settings[i].name, settings[i].value);
    }
}
