#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>
#include <unistd.h>

#define MAX_TASKS 100
#define TASK_NAME_LEN 256

typedef enum {WAITING, RUNNING, COMPLETED, CANCELLED} TaskStatus;

typedef struct {
    char name[TASK_NAME_LEN];
    int duration;
    TaskStatus status;
} Task;

Task task_list[MAX_TASKS];
int task_count = 0;
pthread_mutex_t task_mutex;

void ADD_TASK(const char *task_name, int duration) {
    pthread_mutex_lock(&task_mutex);

    if (task_count >= MAX_TASKS) {
        printf("Task limit reached.\n");
        pthread_mutex_unlock(&task_mutex);
        return;
    }

    strcpy(task_list[task_count].name, task_name);
    task_list[task_count].duration = duration;
    task_list[task_count].status = WAITING;
    task_count++;

    printf("Task '%s' added.\n", task_name);

    pthread_mutex_unlock(&task_mutex);
}

void *task_runner(void *arg) {
    Task *task = (Task *)arg;
    task->status = RUNNING;
    sleep(task->duration);
    task->status = COMPLETED;
    printf("Task '%s' completed.\n", task->name);
    return NULL;
}

void START_TASK(const char *task_name) {
    pthread_mutex_lock(&task_mutex);

    for (int i = 0; i < task_count; i++) {
        if (strcmp(task_list[i].name, task_name) == 0) {
            if (task_list[i].status == WAITING) {
                pthread_t task_thread;
                pthread_create(&task_thread, NULL, task_runner, &task_list[i]);
                pthread_detach(task_thread);
                pthread_mutex_unlock(&task_mutex);
                return;
            }
            printf("Task '%s' is already running or completed.\n", task_name);
            pthread_mutex_unlock(&task_mutex);
            return;
        }
    }

    printf("Task '%s' not found.\n", task_name);
    pthread_mutex_unlock(&task_mutex);
}

void CHECK_TASK(const char *task_name) {
    pthread_mutex_lock(&task_mutex);

    for (int i = 0; i < task_count; i++) {
        if (strcmp(task_list[i].name, task_name) == 0) {
            const char *status_str;
            switch (task_list[i].status) {
                case WAITING: status_str = "Waiting"; break;
                case RUNNING: status_str = "Running"; break;
                case COMPLETED: status_str = "Completed"; break;
                case CANCELLED: status_str = "Cancelled"; break;
            }
            printf("Task '%s' status: %s\n", task_name, status_str);
            pthread_mutex_unlock(&task_mutex);
            return;
        }
    }

    printf("Task '%s' not found.\n", task_name);
    pthread_mutex_unlock(&task_mutex);
}

void CANCEL_TASK(const char *task_name) {
    pthread_mutex_lock(&task_mutex);

    for (int i = 0; i < task_count; i++) {
        if (strcmp(task_list[i].name, task_name) == 0) {
            if (task_list[i].status == WAITING || task_list[i].status == RUNNING) {
                task_list[i].status = CANCELLED;
                printf("Task '%s' cancelled.\n", task_name);
                pthread_mutex_unlock(&task_mutex);
                return;
            }
            printf("Task '%s' cannot be cancelled.\n", task_name);
            pthread_mutex_unlock(&task_mutex);
            return;
        }
    }

    printf("Task '%s' not found.\n", task_name);
    pthread_mutex_unlock(&task_mutex);
}

int main() {
    pthread_mutex_init(&task_mutex, NULL);

    ADD_TASK("Task1", 5);
    START_TASK("Task1");
    sleep(1);
    CHECK_TASK("Task1");
    sleep(6);
    CHECK_TASK("Task1");

    pthread_mutex_destroy(&task_mutex);
    return 0;
}
