class FileManager {
public:
    FileManager() : fileStream() {}

    bool openFile(const std::string& fileName) {
        fileStream.open(fileName, std::ios::in | std::ios::out | std::ios::app);
        if (!fileStream.is_open()) {
            std::cerr << "Error: Could not open the file: " << fileName << std::endl;
            return false;
        }
        return true;
    }

    bool writeFile(const std::string& data) {
        if (!fileStream.is_open()) {
            std::cerr << "Error: No file is open for writing." << std::endl;
            return false;
        }
        fileStream << data;
        if (fileStream.fail()) {
            std::cerr << "Error: Writing to file failed." << std::endl;
            return false;
        }
        return true;
    }

    std::string readFile() {
        if (!fileStream.is_open()) {
            std::cerr << "Error: No file is open for reading." << std::endl;
            return "";
        }
        fileStream.seekg(0);
        std::string content((std::istreambuf_iterator<char>(fileStream)), std::istreambuf_iterator<char>());
        if (fileStream.fail() && !fileStream.eof()) {
            std::cerr << "Error: Reading from file failed." << std::endl;
            return "";
        }
        return content;
    }

    bool closeFile() {
        if (fileStream.is_open()) {
            fileStream.close();
            if (fileStream.fail()) {
                std::cerr << "Error: Closing file failed." << std::endl;
                return false;
            }
        }
        return true;
    }

protected:

private:
    std::fstream fileStream;
};
