fn add(num1: i32, num2: i32) -> i32 {
    let result: i32 = num1 + num2;
    result
}

fn subtract(num1: i32, num2: i32) -> i32 {
    let result: i32 = num1 - num2;
    result
}

fn multiply(num1: i32, num2: i32) -> i32 {
    let result: i32 = num1 * num2;
    result
}

fn divide(num1: i32, num2: i32) -> Result<i32, &'static str> {
    if num2 == 0 {
        return Err("Error: Division by zero");
    }
    let result: i32 = num1 / num2;
    Ok(result)
}

fn main() {
    let args: Vec<String> = env::args().collect();

    if args.len() != 4 {
        eprintln!("Usage: {} <OPERATION> <num1> <num2>", args[0]);
        process::exit(1);
    }

    let operation: &str = &args[1];
    let num1: i32 = args[2].parse().unwrap_or_else(|_| {
        eprintln!("Error: The first number is not a valid integer.");
        process::exit(1);
    });
    let num2: i32 = args[3].parse().unwrap_or_else(|_| {
        eprintln!("Error: The second number is not a valid integer.");
        process::exit(1);
    });

    let result = match operation {
        "ADD" => add(num1, num2).to_string(),
        "SUBTRACT" => subtract(num1, num2).to_string(),
        "MULTIPLY" => multiply(num1, num2).to_string(),
        "DIVIDE" => match divide(num1, num2) {
            Ok(res) => res.to_string(),
            Err(err) => err.to_string(),
        },
        _ => {
            eprintln!("Error: Unsupported operation. Use ADD, SUBTRACT, MULTIPLY, DIVIDE.");
            process::exit(1);
        }
    };

    println!("{}", result);
}
