function manageShoppingCart() {
  // Initialize an empty shopping cart object
  var cart = {};

  // Function to add a product to the shopping cart
  // @param {string} productId - The unique identifier for the product
  // @param {number} quantity - The quantity of the product to add
  function addProduct(productId, quantity) {
    var currentQuantity;

    if (cart[productId]) {
      currentQuantity = cart[productId];
      cart[productId] = currentQuantity + quantity;
    } else {
      cart[productId] = quantity;
    }
  }

  // Function to remove a product from the shopping cart
  // @param {string} productId - The unique identifier for the product
  // @returns {string} - A message indicating success or failure
  function removeProduct(productId) {
    if (cart.hasOwnProperty(productId)) {
      delete cart[productId];
      return 'Product removed successfully.';
    } else {
      return 'Invalid productId: Product not found.';
    }
  }

  // Function to update the quantity of a product in the shopping cart
  // @param {string} productId - The unique identifier for the product
  // @param {number} quantity - The new quantity of the product
  // @returns {string} - A message indicating success or failure
  function updateProduct(productId, quantity) {
    if (cart.hasOwnProperty(productId)) {
      cart[productId] = quantity;
      return 'Product quantity updated successfully.';
    } else {
      return 'Invalid productId: Product not found.';
    }
  }

  // Function to get the quantity of a product in the shopping cart
  // @param {string} productId - The unique identifier for the product
  // @returns {number|string} - Returns the quantity if found or a message indicating failure
  function getProduct(productId) {
    if (cart.hasOwnProperty(productId)) {
      return cart[productId];
    } else {
      return 'Invalid productId: Product not found.';
    }
  }

  // Return an object containing the operations that can be performed on the cart
  return {
    addProduct: addProduct,
    removeProduct: removeProduct,
    updateProduct: updateProduct,
    getProduct: getProduct
  };
}
