#include <arpa/inet.h>
#include <sys/types.h>
#include <sys/socket.h>
#include <sys/sysinfo.h>

#define PORT 8080

class Server {
public:
    void startServer();

protected:
    void handleClient(int clientSocket);

private:
    int serverSocket;
    struct sockaddr_in serverAddr, clientAddr;
    socklen_t addrLen;
};

void Server::startServer() {
    serverSocket = socket(AF_INET, SOCK_STREAM, 0);
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_addr.s_addr = INADDR_ANY;
    serverAddr.sin_port = htons(PORT);
    bind(serverSocket, (struct sockaddr*)&serverAddr, sizeof(serverAddr));
    listen(serverSocket, 3);

    addrLen = sizeof(clientAddr);
    while (1) {
        int clientSocket = accept(serverSocket, (struct sockaddr*)&clientAddr, &addrLen);
        handleClient(clientSocket);
        close(clientSocket);
    }
}

void Server::handleClient(int clientSocket) {
    char buffer[1024] = {0};
    read(clientSocket, buffer, sizeof(buffer));

    if (strcmp(buffer, "CPU_USAGE") == 0) {
        double cpuUsage = get_nprocs_conf() - get_nprocs();
        snprintf(buffer, sizeof(buffer), "CPU Usage: %.2f%%", cpuUsage);
    } else if (strcmp(buffer, "MEMORY_USAGE") == 0) {
        struct sysinfo info;
        sysinfo(&info);
        double memoryUsage = ((info.totalram - info.freeram) / (double)info.totalram) * 100;
        snprintf(buffer, sizeof(buffer), "Memory Usage: %.2f%%", memoryUsage);
    } else if (strcmp(buffer, "DISK_USAGE") == 0) {
        // Disk Usage logic (requires additional implementation)
        snprintf(buffer, sizeof(buffer), "Disk Usage: Not Implemented");
    } else {
        snprintf(buffer, sizeof(buffer), "Invalid Command");
    }

    send(clientSocket, buffer, strlen(buffer), 0);
}

int main() {
    Server server;
    server.startServer();
    return 0;
}

