class Playlist {
private:
    std::vector<std::string> songs;
    std::mutex mtx;
    size_t current_song;

public:
    Playlist() : current_song(0) {}

    void addSong(const std::string& song_name) {
        std::lock_guard<std::mutex> lock(mtx);
        songs.push_back(song_name);
        std::cout << "Added: " << song_name << std::endl;
    }

    void removeSong(const std::string& song_name) {
        std::lock_guard<std::mutex> lock(mtx);
        auto it = std::find(songs.begin(), songs.end(), song_name);
        if (it != songs.end()) {
            songs.erase(it);
            std::cout << "Removed: " << song_name << std::endl;
            if (current_song >= songs.size() && current_song > 0) current_song--;
        } else {
            std::cout << "Error: Song not found - " << song_name << std::endl;
        }
    }

    void play() {
        std::lock_guard<std::mutex> lock(mtx);
        if (!songs.empty() && current_song < songs.size()) {
            std::cout << "Playing: " << songs[current_song] << std::endl;
            current_song++;
        } else {
            std::cout << "No more songs to play." << std::endl;
        }
    }

    void listSongs() {
        std::lock_guard<std::mutex> lock(mtx);
        if (songs.empty()) {
            std::cout << "Playlist is empty." << std::endl;
        } else {
            std::cout << "Playlist:" << std::endl;
            for (const auto& song : songs) {
                std::cout << song << std::endl;
            }
        }
    }
};

int main() {
    Playlist playlist;
    std::string command, song_name;

    while (true) {
        std::cin >> command;
        if (command == "ADD") {
            std::cin.ignore();
            std::getline(std::cin, song_name);
            playlist.addSong(song_name);
        } else if (command == "REMOVE") {
            std::cin.ignore();
            std::getline(std::cin, song_name);
            playlist.removeSong(song_name);
        } else if (command == "PLAY") {
            playlist.play();
        } else if (command == "LIST") {
            playlist.listSongs();
        } else {
            std::cout << "Invalid command" << std::endl;
        }
    }

    return 0;
}
