public class PaymentProcessor {
    public static List<Double> processPayments(List<Double> amounts, double feeRate) {
        List<Double> processedAmounts = new ArrayList<>();
        int i = 0;
        int size = amounts.size();

        while (i < size) {
            double amount = amounts.get(i);
            double fee = amount * feeRate;
            double reducedAmount = amount - fee;
            processedAmounts.add(reducedAmount);
            i++;
        }

        return processedAmounts;
    }
