#define ADD "ADD"
#define SUBTRACT "SUBTRACT"
#define MULTIPLY "MULTIPLY"
#define DIVIDE "DIVIDE"
#define ERROR_DIV_ZERO "Error: Division by zero is undefined."

void command_line_calculator() {
    char command[100];
    int operand1, operand2;

    while (1) {
        printf("Enter command: ");
        if (fgets(command, sizeof(command), stdin) == NULL) {
            break; // EOF detected
        }

        if (strncmp(command, ADD, strlen(ADD)) == 0) {
            sscanf(command, "%*s %d %d", &operand1, &operand2);
            printf("%d\n", operand1 + operand2);
        } else if (strncmp(command, SUBTRACT, strlen(SUBTRACT)) == 0) {
            sscanf(command, "%*s %d %d", &operand1, &operand2);
            printf("%d\n", operand1 - operand2);
        } else if (strncmp(command, MULTIPLY, strlen(MULTIPLY)) == 0) {
            sscanf(command, "%*s %d %d", &operand1, &operand2);
            printf("%d\n", operand1 * operand2);
        } else if (strncmp(command, DIVIDE, strlen(DIVIDE)) == 0) {
            sscanf(command, "%*s %d %d", &operand1, &operand2);
            if (operand2 == 0) {
                printf("%s\n", ERROR_DIV_ZERO);
            } else {
                printf("%d\n", operand1 / operand2);
            }
        } else {
            printf("Invalid command.\n");
        }
    }
}

int main() {
    command_line_calculator();
    return 0;
}
