use std::collections::HashMap;
use std::io::{Read, Write};
use std::net::{TcpListener, TcpStream};
use std::sync::{Arc, Mutex};
use std::thread;
use std::sync::mpsc::{self, Sender, Receiver};

type UserList = Arc<Mutex<HashMap<String, TcpStream>>>;

fn main() {
    let listener = TcpListener::bind("127.0.0.1:8080").expect("Could not bind");
    let users: UserList = Arc::new(Mutex::new(HashMap::new()));

    for stream in listener.incoming() {
        match stream {
            Ok(stream) => {
                let users = Arc::clone(&users);
                thread::spawn(move || handle_client(stream, users));
            }
            Err(e) => {
                eprintln!("Connection failed: {}", e);
            }
        }
    }
}

fn handle_client(mut stream: TcpStream, users: UserList) {
    let mut username = String::new();
    let (tx, rx): (Sender<String>, Receiver<String>) = mpsc::channel();
    let clone_stream = stream.try_clone().expect("Failed to clone stream");
    thread::spawn(move || listen_for_messages(clone_stream, rx));

    loop {
        let mut buffer = [0; 512];
        let bytes_read = stream.read(&mut buffer).expect("Failed to read");
        if bytes_read == 0 {
            users.lock().unwrap().remove(&username);
            broadcast(&users, &format!("{} has left the chat", username));
            break;
        }

        let input = String::from_utf8_lossy(&buffer[..bytes_read]).trim().to_string();
        if input.starts_with("JOIN ") {
            username = input[5..].to_string();
            users.lock().unwrap().insert(username.clone(), stream.try_clone().expect("Failed to clone stream"));
            broadcast(&users, &format!("{} has joined the chat", username));
        } else if input == "LEAVE" {
            users.lock().unwrap().remove(&username);
            broadcast(&users, &format!("{} has left the chat", username));
            break;
        } else if input.starts_with("MESSAGE ") {
            let msg = format!("{}: {}", username, &input[8..]);
            broadcast(&users, &msg);
        } else if input == "LIST" {
            let user_list = users.lock().unwrap().keys().cloned().collect::<Vec<String>>().join(", ");
            let _ = tx.send(format!("Currently connected users: {}", user_list));
        }
    }
}

fn listen_for_messages(mut stream: TcpStream, rx: Receiver<String>) {
    for msg in rx {
        let _ = stream.write(msg.as_bytes());
    }
}

fn broadcast(users: &UserList, msg: &str) {
    for (_, user_stream) in users.lock().unwrap().iter_mut() {
        let mut clone_stream = user_stream.try_clone().expect("Failed to clone stream");
        let _ = clone_stream.write(msg.as_bytes());
    }
}
