class Food {
    private String name;
    private double calories;
    private double carbs;
    private double protein;
    private double fats;

    public Food(String name, double calories, double carbs, double protein, double fats) {
        this.name = name;
        this.calories = calories;
        this.carbs = carbs;
        this.protein = protein;
        this.fats = fats;
    }

    public double getCalories() {
        return calories;
    }

    public double getCarbs() {
        return carbs;
    }

    public double getProtein() {
        return protein;
    }

    public double getFats() {
        return fats;
    }
}

public class NutritionCalculator {
    private List<Food> foodList;

    public NutritionCalculator() {
        foodList = new ArrayList<>();
    }

    public void addFood(String foodName, double calories, double carbs, double protein, double fats) {
        double validCalories = calories >= 0 ? calories : 0;
        double validCarbs = carbs >= 0 ? carbs : 0;
        double validProtein = protein >= 0 ? protein : 0;
        double validFats = fats >= 0 ? fats : 0;

        Food foodItem = new Food(foodName, validCalories, validCarbs, validProtein, validFats);
        foodList.add(foodItem);
    }

    public double[] totalNutrition() {
        double totalCalories = 0;
        double totalCarbs = 0;
        double totalProtein = 0;
        double totalFats = 0;

        for (Food food : foodList) {
            double currentCalories = food.getCalories();
            double currentCarbs = food.getCarbs();
            double currentProtein = food.getProtein();
            double currentFats = food.getFats();

            totalCalories += currentCalories;
            totalCarbs += currentCarbs;
            totalProtein += currentProtein;
            totalFats += currentFats;
        }

        double[] totalNutritionalValues = {totalCalories, totalCarbs, totalProtein, totalFats};
        return totalNutritionalValues;
    }

    public static void main(String[] args) {
