        Scanner scanner = new Scanner(System.in);

        int numberOfFoods = 0;
        System.out.print("Enter the number of food items: ");
        numberOfFoods = scanner.nextInt();

        for (int i = 0; i < numberOfFoods; i++) {
            String foodName = "";
            double calories = 0;
            double carbs = 0;
            double protein = 0;
            double fats = 0;

