#define MAX_ACCOUNTS 100

typedef struct {
    int customerId;
    double balance;
    int isActive;
} Account;

Account accounts[MAX_ACCOUNTS];
int totalAccounts = 0;

void createAccount(int customerId, double initialBalance) {
    if (totalAccounts >= MAX_ACCOUNTS) {
        printf("Error: Maximum account limit reached.\n");
        return;
    }
    for (int i = 0; i < totalAccounts; i++) {
        if (accounts[i].customerId == customerId && accounts[i].isActive) {
            printf("Error: Customer ID already exists.\n");
            return;
        }
    }
    accounts[totalAccounts].customerId = customerId;
    accounts[totalAccounts].balance = initialBalance;
    accounts[totalAccounts].isActive = 1;
    totalAccounts++;
    printf("Account created successfully.\n");
}

void deposit(int customerId, double amount) {
    for (int i = 0; i < totalAccounts; i++) {
        if (accounts[i].customerId == customerId && accounts[i].isActive) {
            accounts[i].balance += amount;
            printf("Deposit successful. New balance: %.2f\n", accounts[i].balance);
            return;
        }
    }
    printf("Error: Customer ID not found.\n");
}

void withdraw(int customerId, double amount) {
    for (int i = 0; i < totalAccounts; i++) {
        if (accounts[i].customerId == customerId && accounts[i].isActive) {
            if (accounts[i].balance >= amount) {
                accounts[i].balance -= amount;
                printf("Withdrawal successful. New balance: %.2f\n", accounts[i].balance);
            } else {
                printf("Error: Insufficient balance.\n");
            }
            return;
        }
    }
    printf("Error: Customer ID not found.\n");
}

void getBalance(int customerId) {
    for (int i = 0; i < totalAccounts; i++) {
        if (accounts[i].customerId == customerId && accounts[i].isActive) {
            printf("Current balance: %.2f\n", accounts[i].balance);
            return;
        }
    }
    printf("Error: Customer ID not found.\n");
}

void closeAccount(int customerId) {
    for (int i = 0; i < totalAccounts; i++) {
        if (accounts[i].customerId == customerId && accounts[i].isActive) {
            accounts[i].isActive = 0;
            printf("Account closed successfully.\n");
            return;
        }
    }
    printf("Error: Customer ID not found.\n");
}

int main() {
    // Example actions
    createAccount(1, 1000.0);
    deposit(1, 200.0);
    withdraw(1, 50.0);
    getBalance(1);
    closeAccount(1);
    return 0;
