#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_TASKS 100

typedef struct {
    int task_id;
    int priority;
} Task;

Task task_list[MAX_TASKS];
int task_count = 0;

int find_task_index(int task_id) {
    for (int i = 0; i < task_count; i++) {
        if (task_list[i].task_id == task_id) {
            return i;
        }
    }
    return -1;
}

void add_task(int task_id, int priority) {
    if (find_task_index(task_id) != -1) {
        printf("Error: Task ID %d already exists.\n", task_id);
        return;
    }
    if (task_count >= MAX_TASKS) {
        printf("Error: Maximum task limit reached.\n");
        return;
    }
    task_list[task_count].task_id = task_id;
    task_list[task_count].priority = priority;
    task_count++;
    printf("Task %d added with priority %d.\n", task_id, priority);
}

void remove_task(int task_id) {
    int index = find_task_index(task_id);
    if (index == -1) {
        printf("Error: Task ID %d does not exist.\n", task_id);
        return;
    }
    for (int i = index; i < task_count - 1; i++) {
        task_list[i] = task_list[i + 1];
    }
    task_count--;
    printf("Task %d removed.\n", task_id);
}

void change_priority(int task_id, int new_priority) {
    int index = find_task_index(task_id);
    if (index == -1) {
        printf("Error: Task ID %d does not exist.\n", task_id);
        return;
    }
    task_list[index].priority = new_priority;
    printf("Priority of task %d changed to %d.\n", task_id, new_priority);
}

void fetch_next_task() {
    if (task_count == 0) {
        printf("No tasks available.\n");
        return;
    }
    int highest_priority_index = 0;
    for (int i = 1; i < task_count; i++) {
        if (task_list[i].priority > task_list[highest_priority_index].priority) {
            highest_priority_index = i;
        }
    }
    int task_id = task_list[highest_priority_index].task_id;
    printf("Next task fetched: ID %d with priority %d.\n", task_id, task_list[highest_priority_index].priority);
    remove_task(task_id);
}

int main() {
    // Sample operations
    add_task(1, 10);
    add_task(2, 20);
    add_task(3, 15);

    fetch_next_task();
    change_priority(3, 25);
    remove_task(2);

    fetch_next_task();
    return 0;
}
