function calculateTimeSpan(startTimeStamp, endTimeStamp) {
    const secondsPerMinute = 60;
    const minutesPerHour = 60;
    const hoursPerDay = 24;
    const daysPerYear = 365;
    const monthsPerYear = 12;

    let start, end, diffInSeconds, years, months, days, hours, minutes, seconds;

    if (typeof startTimeStamp !== 'number' || typeof endTimeStamp !== 'number') {
        throw new Error('Invalid input: Both timestamps must be numbers.');
    }

    start = new Date(startTimeStamp);
    end = new Date(endTimeStamp);

    if (isNaN(start) || isNaN(end)) {
        throw new Error('Invalid input: One or both timestamps are invalid dates.');
    }

    if (endTimeStamp < startTimeStamp) {
        throw new Error('Invalid input: endTimeStamp must be greater than or equal to startTimeStamp.');
    }

    diffInSeconds = Math.floor((endTimeStamp - startTimeStamp) / 1000);

    years = Math.floor(diffInSeconds / (secondsPerMinute * minutesPerHour * hoursPerDay * daysPerYear));
    diffInSeconds %= secondsPerMinute * minutesPerHour * hoursPerDay * daysPerYear;

    months = Math.floor(diffInSeconds / (secondsPerMinute * minutesPerHour * hoursPerDay * (daysPerYear / monthsPerYear)));
    diffInSeconds %= secondsPerMinute * minutesPerHour * hoursPerDay * (daysPerYear / monthsPerYear);

    days = Math.floor(diffInSeconds / (secondsPerMinute * minutesPerHour * hoursPerDay));
    diffInSeconds %= secondsPerMinute * minutesPerHour * hoursPerDay;

    hours = Math.floor(diffInSeconds / (secondsPerMinute * minutesPerHour));
    diffInSeconds %= secondsPerMinute * minutesPerHour;

    minutes = Math.floor(diffInSeconds / secondsPerMinute);
    seconds = diffInSeconds % secondsPerMinute;

    return {
        years,
        months,
        days,
        hours,
        minutes,
        seconds
    };
}
