        if (it != passengerList.end()) {
            passengerList.erase(it, passengerList.end());
            std::cout << "Canceled booking for " << passengerName << " on flight " << flightID << "\n";
        } else {
            std::cout << passengerName << " not found on flight " << flightID << "\n";
        }
    }

    void flightList() const {
        for (const auto& [flightID, passengers] : flights) {
            std::cout << "Flight: " << flightID << ", Booked Passengers: " << passengers.size() << "\n";
        }
    }

    void passengerList(const std::string& flightID) const {
        auto it = flights.find(flightID);
        if (it != flights.end()) {
