import java.util.HashSet;
import java.util.Set;

public class ParkingGarageSystem {
    private int totalSpaces = 100;
    private Set<String> parkedVehicles = new HashSet<>();

    public String parkVehicle(String licensePlate) {
        if (parkedVehicles.size() >= totalSpaces) {
            return "No spots available.";
        }
        if (!parkedVehicles.add(licensePlate)) {
            return "Vehicle is already parked.";
        }
        return "Vehicle parked successfully.";
    }

    public String departVehicle(String licensePlate) {
        if (!parkedVehicles.remove(licensePlate)) {
            return "Vehicle not found.";
        }
        return "Vehicle departed successfully.";
    }

    public int countAvailableSpaces() {
        return totalSpaces - parkedVehicles.size();
    }

    public static void main(String[] args) {
        ParkingGarageSystem garage = new ParkingGarageSystem();
        System.out.println(garage.parkVehicle("ABC123"));
        System.out.println(garage.departVehicle("XYZ789"));
        System.out.println(garage.countAvailableSpaces());
    }
}
