import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@SpringBootApplication
public class ProfileServiceApplication {
    public static void main(String[] args) {
        SpringApplication.run(ProfileServiceApplication.class, args);
    }
}

@RestController
@RequestMapping("/profiles")
class ProfileController {

    private final Map<String, UserProfile> profileStore = new HashMap<>();

    @PostMapping
    public ResponseEntity<String> createProfile(@RequestBody UserProfile profile) {
        if (profileStore.containsKey(profile.getUsername())) {
            return new ResponseEntity<>("Profile already exists", HttpStatus.CONFLICT);
        }
        profileStore.put(profile.getUsername(), profile);
        return new ResponseEntity<>("Profile created", HttpStatus.CREATED);
    }

    @GetMapping("/{username}")
    public ResponseEntity<UserProfile> readProfile(@PathVariable String username) {
        UserProfile profile = profileStore.get(username);
        if (profile == null) {
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
        return new ResponseEntity<>(profile, HttpStatus.OK);
    }

    @PutMapping("/{username}")
    public ResponseEntity<String> updateProfile(@PathVariable String username, @RequestBody Map<String, Object> updates) {
        UserProfile profile = profileStore.get(username);
        if (profile == null) {
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
        if (updates.containsKey("email")) {
            profile.setEmail((String) updates.get("email"));
        }
        if (updates.containsKey("age")) {
            profile.setAge((int) updates.get("age"));
        }
        return new ResponseEntity<>("Profile updated", HttpStatus.OK);
    }

    @DeleteMapping("/{username}")
    public ResponseEntity<Void> deleteProfile(@PathVariable String username) {
        if (profileStore.remove(username) == null) {
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        }
        return new ResponseEntity<>(HttpStatus.NO_CONTENT);
    }
}

