#include <iostream>

struct Node {
    int data;
    Node* next;
};

class Stack {
private:
    Node* top;
    int currentSize;

public:
    // Constructor
    Stack() : top(nullptr), currentSize(0) {}

    // Push operation
    void push(int value) {
        Node* newNode = new Node;
        newNode->data = value;
        newNode->next = top;
        top = newNode;
        currentSize++;
    }

    // Pop operation
    void pop() {
        if (!isEmpty()) {
            Node* temp = top;
            top = top->next;
            delete temp;
            currentSize--;
        } else {
            std::cerr << "Stack is empty\n";
        }
    }

    // Peek operation
    int peek() {
        if (!isEmpty()) {
            return top->data;
        } else {
            std::cerr << "Stack is empty\n";
            return -1; // Return a default value if empty; should handle differently in practice
        }
    }

    // Size function
    int size() {
        return currentSize;
    }

    // isEmpty function
    bool isEmpty() {
        return top == nullptr;
    }
};

int main() {
    Stack myStack;
    myStack.push(10);
    myStack.push(20);
    std::cout << "Top element is: " << myStack.peek() << "\n";
    std::cout << "Stack size is: " << myStack.size() << "\n";
    myStack.pop();
    std::cout << "Stack size after pop is: " << myStack.size() << "\n";
    std::cout << "Stack isEmpty: " << (myStack.isEmpty() ? "true" : "false") << "\n";

    return 0;
}
