function isRequestAllowed() {
    const maxCallsPerMinute = 100;
    const refillIntervalInMilliseconds = 60000;

    let tokens;
    let lastRefillTimestamp;

    if (typeof isRequestAllowed.maxCallsAtTheMoment === 'undefined') {
        isRequestAllowed.maxCallsAtTheMoment = maxCallsPerMinute;
        isRequestAllowed.lastRefillTimestamp = Date.now();
    }

    tokens = isRequestAllowed.maxCallsAtTheMoment;
    lastRefillTimestamp = isRequestAllowed.lastRefillTimestamp;

    const currentTimestamp = Date.now();
    const elapsedMilliseconds = currentTimestamp - lastRefillTimestamp;
    const refillTokens = Math.floor(elapsedMilliseconds / refillIntervalInMilliseconds) * maxCallsPerMinute;

    if (refillTokens > 0) {
        tokens = Math.min(maxCallsPerMinute, tokens + refillTokens);
        isRequestAllowed.lastRefillTimestamp = currentTimestamp;
    }

    if (tokens > 0) {
        isRequestAllowed.maxCallsAtTheMoment = tokens - 1;
        return true;
    } else {
        return false;
    }
}
