class Cache:
    def __init__(self, max_items=100):
        self.max_items = max_items
        self.cache_storage = {}
        self.access_order = []

    def add_item(self, key, value):
        if key in self.cache_storage:
            self.access_order.remove(key)
        elif len(self.cache_storage) >= self.max_items:
            least_recently_used_key = self.access_order.pop(0)
            del self.cache_storage[least_recently_used_key]

        self.cache_storage[key] = value
        self.access_order.append(key)

    def get_item(self, key):
        if key not in self.cache_storage:
            raise KeyError(f"Key '{key}' not found in cache")

        self.access_order.remove(key)
        self.access_order.append(key)
        return self.cache_storage[key]

    def remove_item(self, key):
        if key in self.cache_storage:
            del self.cache_storage[key]
            self.access_order.remove(key)
        else:
            raise KeyError(f"Key '{key}' not found in cache")

    def clear_cache(self):
        self.cache_storage.clear()
        self.access_order.clear()
