#include <iostream>
#include <unordered_map>
#include <mutex>
#include <string>

class InMemoryDatabase {
private:
    std::unordered_map<std::string, std::string> storage;
    std::mutex mtx;

public:
    void set(const std::string& key, const std::string& value) {
        std::lock_guard<std::mutex> lock(mtx);
        storage[key] = value;
    }

    std::string get(const std::string& key) {
        std::lock_guard<std::mutex> lock(mtx);
        if (storage.find(key) != storage.end()) {
            return storage[key];
        } else {
            return "Error: Key not found";
        }
    }

    std::string deleteKey(const std::string& key) {
        std::lock_guard<std::mutex> lock(mtx);
        if (storage.erase(key)) {
            return "Key deleted successfully";
        } else {
            return "Error: Key not found";
        }
    }

    std::string update(const std::string& key, const std::string& value) {
        std::lock_guard<std::mutex> lock(mtx);
        if (storage.find(key) != storage.end()) {
            storage[key] = value;
            return "Key updated successfully";
        } else {
            return "Error: Key not found";
        }
    }
};

int main() {
    InMemoryDatabase db;

    // Example usage of the database
    db.set("name", "Alice");
    std::cout << db.get("name") << std::endl;
    std::cout << db.update("name", "Bob") << std::endl;
    std::cout << db.get("name") << std::endl;
    std::cout << db.deleteKey("name") << std::endl;
    std::cout << db.get("name") << std::endl;

    return 0;
}
